+        .await_expr => |await| isNameUsedInExpr(await.value.*, name),
+        .named_expr => |named| {
+            // Check both target (for assignment) and value
+            if (isNameUsedInExpr(named.target.*, name)) return true;
+            if (isNameUsedInExpr(named.value.*, name)) return true;
